import React, { useState } from 'react';

const EditProject = ({ project, handleUpdate }) => {
    const [editedProject, setEditedProject] = useState({ ...project });

    const handleInputChange = (event) => {
        const { name, value } = event.target;
        setEditedProject((prevProject) => ({
          ...prevProject,
          [name]: value,
        }));
    };

    const handleSubmit = (event) => {
        event.preventDefault();
        handleUpdate(editedProject);
        resetForm();
    };

    const resetForm = () => {
        setEditedProject({
          // Reset the fields as needed for the project
          // Example:
          name: '',
          description: '',
          description: '',
          description: '',
          description: '',
          description: '',
          description: '',
          description: '',
          description: '',
          description: '',
          // Add other fields here
        });
    };

    return (
        <div className="edit-project-container">
            <h2 className="edit-project-heading">Edit Project</h2>
            <form className="edit-project-form" onSubmit={handleSubmit}>
                <div className="form-row">
                    {/* Add form fields as per your project properties */}
                    {/* Example: */}
                    <div className="form-group">
                        <label htmlFor="name">Name:</label>
                        <input
                            type="text"
                            name="name"
                            id="name"
                            value={editedProject.name}
                            onChange={handleInputChange}
                        />
                    </div>
                    <div className="form-group">
                        <label htmlFor="description">Description:</label>
                        <textarea
                            id="description"
                            name="description"
                            value={editedProject.description}
                            onChange={handleInputChange}
                        />
                    </div>
                    {/* Add more fields as needed */}
                </div>
                <button type="submit" className="edit-project-btn">Update</button>
            </form>
        </div>
    );
};

export default EditProject;
